#include<bits/stdc++.h>
using namespace std;
int a[105][105];
int n;
struct node {
	int a, x, y;
};
vector<node> v;
bool cmp(node a, node b) {
	return a.a > b.a;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			cin >> a[i][j];
			node temp;
			temp.a = a[i][j];
			temp.x = i;
			temp.y = j;
			v.push_back(temp);

		}
	}

	sort(v.begin(), v.end(), cmp);
	for (int i = 0; i < v.size(); i++) {
		if (i != 0) {
			if (v[i].a == v[i - 1].a) {
				a[v[i].x][v[i].y] = a[v[i - 1].x][v[i - 1].y];
			} else {
				a[v[i].x][v[i].y] = i + 1;
			}
		} else {
			a[v[i].x][v[i].y] = i + 1;
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			cout << a[i][j] << " ";

		}
		cout << "\n";
	}
}
